import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"魔刀红月晓","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/魔刀红月晓.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/魔刀红月晓.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/魔刀红月晓.md"};function _(l,a,p,i,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"魔刀红月晓",tabindex:"-1"},[s("魔刀红月晓 "),e("a",{class:"header-anchor",href:"#魔刀红月晓","aria-label":'Permalink to "魔刀红月晓"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌037")])])],-1),o('<h1 id="魔刀红月晓-1" tabindex="-1">魔刀红月晓 <a class="header-anchor" href="#魔刀红月晓-1" aria-label="Permalink to &quot;魔刀红月晓&quot;">​</a></h1><p>魔刀红月晓<br> 价格：A+5000<br> 分类：武士刀<br> 武器伤害：30L<br> 武器特性：【破魔1】【法破】【攻击额外获得2个附加成功数】<br> 武器体积：3<br> 伤害类型：特殊（见下）<br> 描述：用太阳和月亮之力狩猎魔物的武士刀。由来有人说是「拂晓」、也有人说是「红月」。<br> 效果：<br> 【日月轮转】： 魔刀红月晓拥有两种形态，消耗一个移动动作即可切换，每轮只能切换一次，同时只有一个形态的效果会生效，初始默认为【红月形态】。</p><p>红月形态： 刀刃上泛起暗红色的微光，如同血月当空。在此形态下，武器伤害类型转为【亵渎伤害】，被该武器击杀的单位视为承受了S级禁止复活的效果影响。<br> 若你从拂晓形态切换至红月形态，则在该场景内红月形态下的该武器改为造成韧性伤害，具有【湮灭】特性。</p><p>拂晓形态： 刀身绽放出金色与白色交融的晨曦之光。在此形态下，武器伤害类型转为【神圣伤害】。若你从红月形态切换至拂晓形态，则在该场景内拂晓形态下的将展开领域，领域范围等同持有者敏感范围。<br> 持有者的近战攻击触及提升至等同领域范围，可以同时对范围内的所有敌对单位造成伤害，并且在持有者的回合结束时，领域会自动使用持有者的攻击预设（无法附带任何招式）进行一次普通攻击，正常具有持有者攻击中的所有效果。在领域范围内，所有友方单位均视为满足【昼】或【白天】或类似环境，但每人只有一个能力可以享受这一满足环境条件的效果（显然的白天条件不是正午），且该领域无法满足超过A级的环境条件需求。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
